#include <stdio.h>
#include <time.h>

void logError(const char* error_msg) {
    FILE* logfile = fopen("error_log.txt", "a");
    if (logfile == NULL) {
        printf("Unable to open log file.\n");
        return;
    }

    time_t rawtime;
    struct tm * timeinfo;
    char buffer[80];

    time (&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(buffer, sizeof(buffer),"%d-%m-%Y %H:%M:%S", timeinfo);
    fprintf(logfile, "[%s] ERROR: %s\n", buffer, error_msg);

    fclose(logfile);
}